    RUN_TEST(test_TC_G6_002_update_uses_percent_units_not_fraction);

    RUN_TEST(test_TC_G7_001_isr_toggles_when_gtm_disabled);
    RUN_TEST(test_TC_G7_002_isr_toggles_when_gtm_enabled);

